"""
MKT Matthew chapters 15-21 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-matthew-15-21.py
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

MATTHEW = {
 "15": {
  "1": {"L":"Then there come to Jesus from Jerusalem Pharisees and scribes, saying:","M":"Then some Pharisees and teachers of the law came to Jesus from Jerusalem and asked:","T":"Some Pharisees and religious scholars came from Jerusalem to challenge Jesus."},
  "2": {"L":"Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.","M":"Why do your disciples break the tradition of the elders? They don't wash their hands before they eat!","T":"Why do your disciples violate the tradition of the elders? They don't wash their hands before eating!"},
  "3": {"L":"And he answered and said unto them: Why do ye also transgress the commandment of God because of your tradition?","M":"Jesus replied: And why do you break the command of God for the sake of your tradition?","T":"Jesus shot back: And why do you break God's commandment for the sake of your tradition?"},
  "4": {"L":"For God said: Honour thy father and thy mother; and: He that speaketh evil of father or mother, let him die the death.","M":"For God said: Honour your father and mother and Anyone who curses their father or mother is to be put to death.","T":"God said: Honor your father and mother—and whoever speaks evil against father or mother must be put to death."},
  "5": {"L":"But ye say: Whosoever shall say to his father or his mother: That wherewith thou mightest have been profited by me is given to God;","M":"But you say that if anyone declares that what might have been used to help their father or mother is devoted to God,","T":"But you say that if someone declares their resources dedicated to God,"},
  "6": {"L":"he shall not honour his father. And ye have made void the word of God because of your tradition.","M":"they are not to honour their father with it. Thus you nullify the word of God for the sake of your tradition.","T":"they're released from the obligation to care for their parents. You have completely cancelled God's word with your tradition."},
  "7": {"L":"Ye hypocrites, well did Isaiah prophesy of you, saying:","M":"You hypocrites! Isaiah was right when he prophesied about you:","T":"You hypocrites—Isaiah described you exactly when he wrote:"},
  "8": {"L":"This people honoureth me with their lips; but their heart is far from me.","M":"These people honour me with their lips, but their hearts are far from me.","T":"These people honor me with words, but their hearts are nowhere near me."},
  "9": {"L":"But in vain do they worship me, teaching as their doctrines the precepts of men.","M":"They worship me in vain; their teachings are merely human rules.","T":"Their worship is hollow—they teach man-made rules as if they were God's commands."},
  "10": {"L":"And he called to him the multitude, and said unto them: Hear, and understand:","M":"Jesus called the crowd to him and said: Listen and understand.","T":"Jesus called the crowd back and said: Listen and get this straight."},
  "11": {"L":"Not that which entereth into the mouth defileth the man; but that which proceedeth out of the mouth, this defileth the man.","M":"What goes into someone's mouth does not defile them, but what comes out of their mouth, that is what defiles them.","T":"It's not what goes into your mouth that makes you unclean before God—it's what comes out of your mouth."},
  "12": {"L":"Then came the disciples, and said unto him: Knowest thou that the Pharisees were offended, when they heard this saying?","M":"Then the disciples came to him and asked: Do you know that the Pharisees were offended when they heard this?","T":"His disciples came to him: Do you know the Pharisees were insulted by what you said?"},
  "13": {"L":"But he answered and said: Every plant which my heavenly Father planted not, shall be rooted up.","M":"He replied: Every plant that my heavenly Father has not planted will be pulled up by the roots.","T":"He replied: Every plant that my heavenly Father didn't plant will be uprooted."},
  "14": {"L":"Let them alone: they are blind guides. And if the blind guide the blind, both shall fall into a pit.","M":"Leave them; they are blind guides. If the blind lead the blind, both will fall into a pit.","T":"Leave them alone. They are blind guides—and when one blind person leads another, they both fall into a ditch."},
  "15": {"L":"And Peter answered and said unto him: Declare unto us the parable.","M":"Peter said: Explain the parable to us.","T":"Peter said: Explain this to us."},
  "16": {"L":"And he said: Are ye also even yet without understanding?","M":"Are you still so dull? Jesus asked them.","T":"Jesus replied: Are you still not getting it?"},
  "17": {"L":"Do ye not perceive that whatsoever goeth into the mouth passeth into the belly, and is cast out into the draught?","M":"Don't you see that whatever enters the mouth goes into the stomach and then out of the body?","T":"Don't you understand that whatever goes into the mouth travels to the stomach and then leaves the body?"},
  "18": {"L":"But the things which proceed out of the mouth come forth out of the heart; and they defile the man.","M":"But the things that come out of a person's mouth come from the heart, and these defile them.","T":"But what comes out of the mouth originates in the heart—and that's what makes a person unclean."},
  "19": {"L":"For out of the heart come forth evil thoughts, murders, adulteries, fornications, thefts, false witness, railings;","M":"For out of the heart come evil thoughts—murder, adultery, sexual immorality, theft, false testimony, slander.","T":"Because out of the heart come evil thoughts, murder, adultery, sexual immorality, theft, false testimony, and slander."},
  "20": {"L":"these are the things which defile the man; but to eat with unwashen hands defileth not the man.","M":"These are what defile a person; but eating with unwashed hands does not defile them.","T":"These are the things that make a person unclean. But eating with unwashed hands doesn't."},
  "21": {"L":"And Jesus went out from thence, and withdrew into the parts of Tyre and Sidon.","M":"Leaving that place, Jesus withdrew to the region of Tyre and Sidon.","T":"Jesus left that area and withdrew to the region of Tyre and Sidon."},
  "22": {"L":"And behold, a Canaanitish woman came out from those borders, and cried, saying: Have mercy on me, O Lord, thou son of David; my daughter is grievously vexed with a demon.","M":"A Canaanite woman from that vicinity came to him, crying out: Lord, Son of David, have mercy on me! My daughter is demon-possessed and suffering terribly.","T":"A Canaanite woman from that area came and cried out: Lord, Son of David, have mercy on me! My daughter is tormented by a demon."},
  "23": {"L":"But he answered her not a word. And his disciples came and besought him, saying: Send her away; for she crieth after us.","M":"Jesus did not answer a word. So his disciples came to him and urged him: Send her away, for she keeps crying out after us.","T":"Jesus said nothing. His disciples came and urged him: Send her away—she won't stop shouting after us."},
  "24": {"L":"But he answered and said: I was not sent but unto the lost sheep of the house of Israel.","M":"He answered: I was sent only to the lost sheep of Israel.","T":"Jesus replied: My mission is specifically to the lost sheep of Israel."},
  "25": {"L":"But she came and worshipped him, saying: Lord, help me.","M":"The woman came and knelt before him. Lord, help me! she said.","T":"But she came and knelt at his feet: Lord, help me!"},
  "26": {"L":"And he answered and said: It is not meet to take the children's bread and cast it to the dogs.","M":"He replied: It is not right to take the children's bread and toss it to the dogs.","T":"He replied: It isn't right to take the children's bread and throw it to the dogs."},
  "27": {"L":"But she said: Yea, Lord; for even the dogs eat of the crumbs which fall from their masters' table.","M":"Yes it is, Lord, she said. Even the dogs eat the crumbs that fall from their master's table.","T":"Yes, Lord, she said—but even dogs eat the scraps that fall from their master's table."},
  "28": {"L":"Then Jesus answered and said unto her: O woman, great is thy faith; be it done unto thee even as thou wilt. And her daughter was healed from that hour.","M":"Then Jesus said to her: Woman, you have great faith! Your request is granted. And her daughter was healed at that moment.","T":"Jesus replied: Woman, your faith is remarkable. What you asked will be done. And her daughter was healed from that moment."},
  "29": {"L":"And Jesus departed thence, and came nigh unto the sea of Galilee; and he went up into the mountain, and sat there.","M":"Jesus left there and went along the Sea of Galilee. Then he went up on a mountainside and sat down.","T":"Jesus moved on from there and went along the shore of the Sea of Galilee. He climbed a hillside and sat down."},
  "30": {"L":"And there came unto him great multitudes, having with them the lame, blind, dumb, maimed, and many others, and they cast them down at his feet; and he healed them;","M":"Great crowds came to him, bringing the lame, the blind, the crippled, the mute and many others, and laid them at his feet; and he healed them.","T":"Huge crowds came to him, bringing the lame, blind, crippled, and mute, and many others. They laid them at his feet, and he healed them."},
  "31": {"L":"insomuch that the multitude wondered, when they saw the dumb speaking, the maimed whole, and the lame walking, and the blind seeing; and they glorified the God of Israel.","M":"The people were amazed when they saw the mute speaking, the crippled made well, the lame walking and the blind seeing. And they praised the God of Israel.","T":"The crowds were astonished—the mute were speaking, the crippled were healed, the lame were walking, and the blind were seeing. They praised the God of Israel."},
  "32": {"L":"And Jesus called unto him his disciples, and said: I have compassion on the multitude, because they continue with me now three days and have nothing to eat; and I would not send them away fasting, lest haply they faint on the way.","M":"Jesus called his disciples to him and said: I have compassion for these people; they have already been with me three days and have nothing to eat. I do not want to send them away hungry, or they may collapse on the way.","T":"Jesus called his disciples: I feel deeply for these people—they've been with me three days and have nothing to eat. I don't want to send them away hungry or they'll collapse before they get home."},
  "33": {"L":"And the disciples say unto him: Whence should we have so many loaves in a desert place as to fill so great a multitude?","M":"His disciples answered: Where could we get enough bread in this remote place to feed such a crowd?","T":"His disciples replied: Where would we find enough bread in this remote place to feed this crowd?"},
  "34": {"L":"And Jesus saith unto them: How many loaves have ye? And they said: Seven, and a few small fishes.","M":"How many loaves do you have? Jesus asked. Seven, they replied, and a few small fish.","T":"How many loaves do you have? Jesus asked. Seven, they said, plus a few small fish."},
  "35": {"L":"And he commanded the multitude to sit down on the ground;","M":"He told the crowd to sit down on the ground.","T":"He told the crowd to sit on the ground."},
  "36": {"L":"and he took the seven loaves and the fishes; and he gave thanks and brake, and gave to the disciples, and the disciples to the multitudes.","M":"Then he took the seven loaves and the fish, and when he had given thanks, he broke them and gave them to the disciples, and they in turn to the people.","T":"He took the seven loaves and the fish, gave thanks, broke them, and gave them to his disciples—who distributed them to the crowd."},
  "37": {"L":"And they all ate, and were filled; and they took up that which remained over of the broken pieces, seven baskets full.","M":"They all ate and were satisfied. Afterwards the disciples picked up seven basketfuls of broken pieces that were left over.","T":"Everyone ate until full. The disciples collected seven large basketfuls of leftovers."},
  "38": {"L":"And they that did eat were four thousand men, beside women and children.","M":"The number of those who ate was four thousand men, besides women and children.","T":"The men alone numbered four thousand, not counting women and children."},
  "39": {"L":"And he sent away the multitudes, and entered into the boat, and came into the borders of Magadan.","M":"After Jesus had sent the crowd away, he got into the boat and went to the vicinity of Magadan.","T":"After dismissing the crowds, Jesus got in the boat and went to the region of Magadan."}
 },
 "16": {
  "1": {"L":"And the Pharisees and Sadducees came, and trying him asked him to show them a sign from heaven.","M":"The Pharisees and Sadducees came to Jesus and tested him by asking him to show them a sign from heaven.","T":"The Pharisees and Sadducees came to test Jesus, demanding that he show them a sign from heaven."},
  "2": {"L":"But he answered and said unto them: When it is evening, ye say: It will be fair weather; for the heaven is red.","M":"He replied: When evening comes, you say: It will be fair weather, for the sky is red,","T":"He replied: In the evening you say, Fine weather coming—the sky is red."},
  "3": {"L":"And in the morning: It will be foul weather to-day; for the heaven is red and lowring. Ye know how to discern the face of the heaven; but ye cannot discern the signs of the times.","M":"and in the morning: Today it will be stormy, for the sky is red and overcast. You know how to interpret the appearance of the sky, but you cannot interpret the signs of the times.","T":"In the morning: Stormy today—the sky is red and threatening. You can read the signs in the sky, but you can't read the signs of what God is doing right now."},
  "4": {"L":"An evil and adulterous generation seeketh after a sign; and there shall no sign be given unto it, but the sign of Jonah. And he left them, and departed.","M":"A wicked and adulterous generation looks for a sign, but none will be given it except the sign of Jonah. Jesus then left them and went away.","T":"A corrupt, unfaithful generation demands signs—but the only sign it will get is the sign of Jonah. And he walked away and left them."},
  "5": {"L":"And the disciples came to the other side and forgot to take bread.","M":"When they went across the lake, the disciples forgot to take bread.","T":"When they crossed to the other side, the disciples realized they had forgotten to bring bread."},
  "6": {"L":"And Jesus said unto them: Take heed and beware of the leaven of the Pharisees and Sadducees.","M":"Be careful, Jesus said to them. Be on your guard against the yeast of the Pharisees and Sadducees.","T":"Jesus warned them: Watch out—be on guard against the yeast of the Pharisees and Sadducees."},
  "7": {"L":"And they reasoned among themselves, saying: We took no bread.","M":"They discussed this among themselves and said: It is because we didn't bring any bread.","T":"They began discussing this among themselves: He must mean we didn't bring bread."},
  "8": {"L":"And Jesus perceiving it said: O ye of little faith, why reason ye among yourselves, because ye have no bread?","M":"Aware of their discussion, Jesus asked: You of little faith, why are you talking among yourselves about having no bread?","T":"Jesus knew what they were thinking: You of such little faith—why are you focused on the fact that you have no bread?"},
  "9": {"L":"Do ye not yet perceive, neither remember the five loaves of the five thousand, and how many baskets ye took up?","M":"Do you still not understand? Don't you remember the five loaves for the five thousand, and how many basketfuls you gathered?","T":"Don't you grasp it yet? Don't you remember the five loaves for five thousand—and how many baskets you filled?"},
  "10": {"L":"Neither the seven loaves of the four thousand, and how many baskets ye took up?","M":"Or the seven loaves for the four thousand, and how many basketfuls you gathered?","T":"Or the seven loaves for four thousand—and how many large baskets you collected?"},
  "11": {"L":"How is it that ye do not perceive that I spake not to you concerning bread? But beware of the leaven of the Pharisees and Sadducees.","M":"How is it you don't understand that I was not talking to you about bread? But be on your guard against the yeast of the Pharisees and Sadducees.","T":"How do you still not see that I wasn't talking about bread? Be on guard against the yeast of the Pharisees and Sadducees."},
  "12": {"L":"Then understood they that he bade them not beware of the leaven of bread, but of the teaching of the Pharisees and Sadducees.","M":"Then they understood that he was not telling them to guard against the yeast used in bread, but against the teaching of the Pharisees and Sadducees.","T":"Then they understood he wasn't talking about bread yeast but about the teaching of the Pharisees and Sadducees."},
  "13": {"L":"Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying: Who do men say that the Son of man is?","M":"When Jesus came to the region of Caesarea Philippi, he asked his disciples: Who do people say the Son of Man is?","T":"When Jesus arrived in the region of Caesarea Philippi, he asked his disciples: Who do people say the Son of Man is?"},
  "14": {"L":"And they said: Some say John the Baptist; some, Elijah; and others, Jeremiah, or one of the prophets.","M":"They replied: Some say John the Baptist; others say Elijah; and still others, Jeremiah or one of the prophets.","T":"They replied: Some say John the Baptist. Others say Elijah. Still others say Jeremiah or one of the prophets."},
  "15": {"L":"He saith unto them: But who say ye that I am?","M":"But what about you? he asked. Who do you say I am?","T":"He pressed them: But who do you say I am?"},
  "16": {"L":"And Simon Peter answered and said: Thou art the Christ, the Son of the living God.","M":"Simon Peter answered: You are the Messiah, the Son of the living God.","T":"Simon Peter said: You are the Messiah—the Son of the living God."},
  "17": {"L":"And Jesus answered and said unto him: Blessed art thou, Simon Bar-Jonah; for flesh and blood hath not revealed it unto thee, but my Father who is in heaven.","M":"Jesus replied: Blessed are you, Simon son of Jonah, for this was not revealed to you by flesh and blood, but by my Father in heaven.","T":"Jesus replied: How blessed you are, Simon son of Jonah—this wasn't revealed to you by human insight but by my Father in heaven."},
  "18": {"L":"And I also say unto thee, that thou art Peter, and upon this rock I will build my church; and the gates of Hades shall not prevail against it.","M":"And I tell you that you are Peter, and on this rock I will build my church, and the gates of Hades will not overcome it.","T":"And I tell you this: you are Peter—the Rock—and on this rock I will build my community, and not even death's gates will be able to stand against it."},
  "19": {"L":"I will give unto thee the keys of the kingdom of heaven; and whatsoever thou shalt bind on earth shall be bound in heaven; and whatsoever thou shalt loose on earth shall be loosed in heaven.","M":"I will give you the keys of the kingdom of heaven; whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven.","T":"I will give you the keys to the heavenly kingdom. Whatever you bind on earth will be bound in heaven, and whatever you release on earth will be released in heaven."},
  "20": {"L":"Then charged he the disciples that they should tell no man that he was the Christ.","M":"Then he ordered his disciples not to tell anyone that he was the Messiah.","T":"Then he instructed his disciples to tell no one that he was the Messiah."},
  "21": {"L":"From that time began Jesus to show unto his disciples, that he must go unto Jerusalem, and suffer many things of the elders and chief priests and scribes, and be killed, and the third day be raised up.","M":"From that time on Jesus began to explain to his disciples that he must go to Jerusalem and suffer many things at the hands of the elders, the chief priests and the teachers of the law, and that he must be killed and on the third day be raised to life.","T":"From that point Jesus began to tell his disciples plainly: He must go to Jerusalem, suffer greatly at the hands of the elders, chief priests, and religious scholars, be killed—and on the third day be raised."},
  "22": {"L":"And Peter took him, and began to rebuke him, saying: Be it far from thee, Lord; this shall never be unto thee.","M":"Peter took him aside and began to rebuke him. Never, Lord! he said. This shall never happen to you!","T":"Peter pulled him aside and began to rebuke him: God forbid, Lord! This must never happen to you!"},
  "23": {"L":"But he turned, and said unto Peter: Get thee behind me, Satan: thou art a stumbling-block unto me; for thou mindest not the things of God, but the things of men.","M":"Jesus turned and said to Peter: Get behind me, Satan! You are a stumbling block to me; you do not have in mind the concerns of God, but merely human concerns.","T":"Jesus turned on him: Get behind me, Satan! You are a stumbling block to me—you're thinking like a human, not like God."},
  "24": {"L":"Then said Jesus unto his disciples: If any man would come after me, let him deny himself, and take up his cross, and follow me.","M":"Then Jesus said to his disciples: Whoever wants to be my disciple must deny themselves and take up their cross and follow me.","T":"Then Jesus said to his disciples: Anyone who wants to follow me must say no to their own desires, shoulder their cross, and come after me."},
  "25": {"L":"For whosoever would save his life shall lose it; and whosoever shall lose his life for my sake shall find it.","M":"For whoever wants to save their life will lose it, but whoever loses their life for me will find it.","T":"Whoever tries to hold onto their life will lose it—but whoever gives their life away for my sake will find it."},
  "26": {"L":"For what shall a man be profited, if he shall gain the whole world, and forfeit his life? or what shall a man give in exchange for his life?","M":"What good will it be for someone to gain the whole world, yet forfeit their soul? Or what can anyone give in exchange for their soul?","T":"What does a person gain if they win the whole world but lose their own soul? And what could they ever offer to buy it back?"},
  "27": {"L":"For the Son of man shall come in the glory of his Father with his angels; and then shall he render unto every man according to his deeds.","M":"For the Son of Man is going to come in his Father's glory with his angels, and then he will reward each person according to what they have done.","T":"Because the Son of Man will come in his Father's glory with his angels—and then he will repay each person according to what they've done."},
  "28": {"L":"Verily I say unto you, There be some of them that stand here, who shall in no wise taste of death, till they see the Son of man coming in his kingdom.","M":"Truly I tell you, some who are standing here will not taste death before they see the Son of Man coming in his kingdom.","T":"I tell you truly—some of those standing here will not die before they see the Son of Man arriving in his kingly power."}
 },
 "17": {
  "1": {"L":"And after six days Jesus taketh with him Peter, and James, and John his brother, and bringeth them up into a high mountain apart;","M":"After six days Jesus took with him Peter, James and John the brother of James, and led them up a high mountain by themselves.","T":"Six days later Jesus took Peter, James, and John up a high mountain by themselves."},
  "2": {"L":"and he was transfigured before them; and his face did shine as the sun, and his garments became white as the light.","M":"There he was transfigured before them. His face shone like the sun, and his clothes became as white as the light.","T":"There, right before their eyes, his appearance was transformed. His face blazed like the sun, and his clothing became dazzling white as light."},
  "3": {"L":"And behold, there appeared unto them Moses and Elijah talking with him.","M":"Just then there appeared before them Moses and Elijah, talking with Jesus.","T":"Suddenly Moses and Elijah appeared and were speaking with him."},
  "4": {"L":"And Peter answered, and said unto Jesus: Lord, it is good for us to be here; if thou wilt, I will make here three tabernacles; one for thee, and one for Moses, and one for Elijah.","M":"Peter said to Jesus: Lord, it is good for us to be here. If you wish, I will put up three shelters—one for you, one for Moses and one for Elijah.","T":"Peter said to Jesus: Lord, it's wonderful that we're here! If you want, I'll set up three shelters—one for you, one for Moses, and one for Elijah."},
  "5": {"L":"While he was yet speaking, behold, a bright cloud overshadowed them; and behold, a voice out of the cloud, saying: This is my beloved Son, in whom I am well pleased; hear ye him.","M":"While he was still speaking, a bright cloud covered them, and a voice from the cloud said: This is my Son, whom I love; with him I am well pleased. Listen to him!","T":"While he was still speaking, a radiant cloud enveloped them, and a voice from the cloud said: This is my Son, the one I love and in whom I delight. Listen to him!"},
  "6": {"L":"And when the disciples heard it, they fell on their face, and were sore afraid.","M":"When the disciples heard this, they fell face down to the ground, terrified.","T":"When the disciples heard this, they threw themselves face-down on the ground in terror."},
  "7": {"L":"And Jesus came and touched them and said: Arise, and be not afraid.","M":"But Jesus came and touched them. Get up, he said. Don't be afraid.","T":"Jesus came and touched them: Get up. Don't be afraid."},
  "8": {"L":"And lifting up their eyes, they saw no one, save Jesus only.","M":"When they looked up, they saw no one except Jesus.","T":"When they raised their eyes, they saw only Jesus."},
  "9": {"L":"And as they were coming down from the mountain, Jesus commanded them, saying: Tell the vision to no man, until the Son of man be risen from the dead.","M":"As they were coming down the mountain, Jesus instructed them: Don't tell anyone what you have seen, until the Son of Man has been raised from the dead.","T":"As they descended the mountain, Jesus instructed them: Don't tell anyone what you've seen until the Son of Man is raised from the dead."},
  "10": {"L":"And his disciples asked him, saying: Why then say the scribes that Elijah must first come?","M":"The disciples asked him: Why then do the teachers of the law say that Elijah must come first?","T":"The disciples asked: Why do the religious scholars say that Elijah must come first?"},
  "11": {"L":"And he answered and said: Elijah indeed cometh, and shall restore all things;","M":"Jesus replied: To be sure, Elijah comes and will restore all things.","T":"Jesus replied: Elijah does come first and will restore everything."},
  "12": {"L":"but I say unto you, that Elijah is come already, and they knew him not, but did unto him whatsoever they would. Even so shall the Son of man also suffer of them.","M":"But I tell you, Elijah has already come, and they did not recognise him, but have done to him everything they wished. In the same way the Son of Man is going to suffer at their hands.","T":"But I tell you—Elijah has already come, and they didn't recognize him. They did whatever they wanted to him. And the Son of Man will suffer at their hands in the same way."},
  "13": {"L":"Then understood the disciples that he spake unto them of John the Baptist.","M":"Then the disciples understood that he was talking to them about John the Baptist.","T":"Then the disciples realized he was talking about John the Baptist."},
  "14": {"L":"And when they were come to the multitude, there came to him a man, kneeling to him, and saying:","M":"When they came to the crowd, a man approached Jesus and knelt before him.","T":"When they rejoined the crowd, a man came and knelt before Jesus."},
  "15": {"L":"Lord, have mercy on my son; for he is epileptic, and suffereth grievously; for oft-times he falleth into the fire, and oft-times into the water.","M":"Lord, have mercy on my son, he said. He has seizures and is suffering greatly. He often falls into the fire or into the water.","T":"Lord, have mercy on my son. He has seizures and suffers terribly—he often falls into fire or water."},
  "16": {"L":"And I brought him to thy disciples, and they could not cure him.","M":"I brought him to your disciples, but they could not heal him.","T":"I brought him to your disciples but they couldn't heal him."},
  "17": {"L":"And Jesus answered and said: O faithless and perverse generation, how long shall I be with you? how long shall I bear with you? bring him hither to me.","M":"You unbelieving and perverse generation, Jesus replied, how long shall I stay with you? How long shall I put up with you? Bring the boy here to me.","T":"Jesus said: You faithless, twisted generation—how long must I stay with you? How long must I put up with you? Bring him here."},
  "18": {"L":"And Jesus rebuked him; and the demon went out from him; and the boy was cured from that hour.","M":"Jesus rebuked the demon, and it came out of the boy, and he was healed at that moment.","T":"Jesus rebuked the demon and it left the boy, who was healed from that moment."},
  "19": {"L":"Then came the disciples to Jesus apart, and said: Why could not we cast it out?","M":"Then the disciples came to Jesus in private and asked: Why couldn't we drive it out?","T":"The disciples came to Jesus privately: Why couldn't we drive it out?"},
  "20": {"L":"And he saith unto them: Because of your little faith; for verily I say unto you, If ye have faith as a grain of mustard seed, ye shall say unto this mountain, Remove hence to yonder place; and it shall remove; and nothing shall be impossible unto you.","M":"He replied: Because you have so little faith. Truly I tell you, if you have faith as small as a mustard seed, you can say to this mountain: Move from here to there, and it will move. Nothing will be impossible for you.","T":"He replied: Because of your small faith. I tell you truly—if your faith were even the size of a mustard seed, you could say to this mountain: Move from here to there—and it would move. Nothing would be impossible."},
  "21": {"L":"But this kind goeth not out but by prayer and fasting.","M":"But this kind does not go out except by prayer and fasting.","T":"But this kind only comes out through prayer and fasting."},
  "22": {"L":"And while they abode in Galilee, Jesus said unto them: The Son of man shall be delivered up into the hands of men;","M":"When they came together in Galilee, he said to them: The Son of Man is going to be delivered into the hands of men.","T":"While they were gathered in Galilee, Jesus said: The Son of Man is about to be handed over into human hands."},
  "23": {"L":"and they shall kill him, and the third day he shall be raised up. And they were exceeding sorry.","M":"They will kill him, and on the third day he will be raised to life. And the disciples were filled with grief.","T":"They will kill him—and on the third day he will be raised. The disciples were filled with grief."},
  "24": {"L":"And when they were come to Capernaum, they that received the half-shekel came to Peter, and said: Doth not your teacher pay the half-shekel?","M":"After Jesus and his disciples arrived in Capernaum, the collectors of the two-drachma temple tax came to Peter and asked: Doesn't your teacher pay the temple tax?","T":"When they arrived in Capernaum, the temple tax collectors came to Peter: Does your teacher pay the temple tax?"},
  "25": {"L":"He saith: Yea. And when he came into the house, Jesus spake first to him, saying: What thinkest thou, Simon? the kings of the earth, from whom do they receive toll or tribute? from their sons, or from strangers?","M":"Yes, he does, he replied. When Peter came into the house, Jesus was the first to speak. What do you think, Simon? he asked. From whom do the kings of the earth collect duty and taxes—from their own children or from others?","T":"Yes, he does, Peter said. When he got home, Jesus spoke first: What do you think, Simon? From whom do earthly kings collect taxes—from their own sons or from others?"},
  "26": {"L":"And when he said: From strangers, Jesus said unto him: Therefore the sons are free.","M":"From others, Peter answered. Then the children are exempt, Jesus said to him.","T":"From others, Peter said. Then the sons are free, Jesus replied."},
  "27": {"L":"But, lest we cause them to stumble, go thou to the sea, and cast a hook, and take up the fish that first cometh up; and when thou hast opened his mouth, thou shalt find a shekel; that take, and give unto them for me and thee.","M":"But so that we may not cause offence, go to the lake and throw out your line. Take the first fish you catch; open its mouth and you will find a four-drachma coin. Take it and give it to them for my tax and yours.","T":"But so we don't give offence—go to the lake, throw in a line, and take the first fish you catch. Open its mouth and you'll find a coin worth exactly enough for both our taxes. Take it and pay them."}
 },
 "18": {
  "1": {"L":"In that hour came the disciples unto Jesus, saying: Who then is greatest in the kingdom of heaven?","M":"At that time the disciples came to Jesus and asked: Who, then, is the greatest in the kingdom of heaven?","T":"At that point the disciples came to Jesus with a question: Who is the greatest in the heavenly kingdom?"},
  "2": {"L":"And he called to him a little child, and set him in the midst of them,","M":"He called a little child to him, and placed the child among them.","T":"He called a small child over and stood the child in the middle of them."},
  "3": {"L":"and said: Verily I say unto you, Except ye turn, and become as little children, ye shall in no wise enter into the kingdom of heaven.","M":"And he said: Truly I tell you, unless you change and become like little children, you will never enter the kingdom of heaven.","T":"I tell you plainly: unless you completely turn around and become like children, you will never enter the heavenly kingdom."},
  "4": {"L":"Whosoever therefore shall humble himself as this little child, the same is the greatest in the kingdom of heaven.","M":"Therefore, whoever takes the lowly position of this child is the greatest in the kingdom of heaven.","T":"So whoever makes themselves as humble as this child is the greatest in the heavenly kingdom."},
  "5": {"L":"And whoso shall receive one such little child in my name receiveth me.","M":"And whoever welcomes one such child in my name welcomes me.","T":"And whoever welcomes a child like this in my name, welcomes me."},
  "6": {"L":"But whoso shall cause one of these little ones that believe on me to stumble, it is profitable for him that a great millstone should be hanged about his neck, and that he should be sunk in the depth of the sea.","M":"If anyone causes one of these little ones—those who believe in me—to stumble, it would be better for them to have a large millstone hung around their neck and to be drowned in the depths of the sea.","T":"But if anyone causes one of these little ones who trust in me to stumble, they would be better off with a heavy millstone hung around their neck and thrown into the deep sea."},
  "7": {"L":"Woe unto the world because of occasions of stumbling! for it must needs be that the occasions come; but woe to that man through whom the occasion cometh.","M":"Woe to the world because of the things that cause people to stumble! Such things must come, but woe to the person through whom they come!","T":"How terrible it will be for the world because of what causes people to stumble! Such stumbling blocks must come—but how terrible for the person who causes them!"},
  "8": {"L":"And if thy hand or thy foot causeth thee to stumble, cut it off, and cast it from thee; it is good for thee to enter into life maimed or halt, rather than having two hands or two feet to be cast into the eternal fire.","M":"If your hand or your foot causes you to stumble, cut it off and throw it away. It is better for you to enter life maimed or crippled than to have two hands or two feet and be thrown into eternal fire.","T":"If your hand or foot is causing you to sin, cut it off and throw it away. Better to enter life crippled than to have both hands and feet and be thrown into eternal fire."},
  "9": {"L":"And if thine eye causeth thee to stumble, pluck it out, and cast it from thee; it is good for thee to enter into life with one eye, rather than having two eyes to be cast into the hell of fire.","M":"And if your eye causes you to stumble, gouge it out and throw it away. It is better for you to enter life with one eye than to have two eyes and be thrown into the fire of hell.","T":"And if your eye is causing you to sin, gouge it out and throw it away. Better to enter life with one eye than to have two eyes and be thrown into Gehenna's fire."},
  "10": {"L":"See that ye despise not one of these little ones; for I say unto you, that in heaven their angels do always behold the face of my Father who is in heaven.","M":"See that you do not despise one of these little ones. For I tell you that their angels in heaven always see the face of my Father in heaven.","T":"Make sure you don't look down on one of these little ones. I tell you, their angels in heaven are continually in the presence of my Father."},
  "11": {"L":"For the Son of man came to save that which was lost.","M":"The Son of Man came to save what was lost.","T":"The Son of Man came to save the lost."},
  "12": {"L":"How think ye? if any man have a hundred sheep, and one of them be gone astray, doth he not leave the ninety and nine, and go unto the mountains, and seek that which goeth astray?","M":"What do you think? If a man owns a hundred sheep, and one of them wanders away, will he not leave the ninety-nine on the hills and go to look for the one that wandered off?","T":"What do you think? If a man has a hundred sheep and one wanders away, won't he leave the ninety-nine on the hillside and go search for the lost one?"},
  "13": {"L":"And if so be that he find it, verily I say unto you, he rejoiceth over it more than over the ninety and nine which have not gone astray.","M":"And if he finds it, truly I tell you, he is happier about that one sheep than about the ninety-nine that did not wander off.","T":"And when he finds it, I tell you—his joy over that one sheep is greater than his joy over the ninety-nine who never wandered."},
  "14": {"L":"Even so it is not the will of your Father who is in heaven, that one of these little ones should perish.","M":"In the same way your Father in heaven is not willing that any of these little ones should perish.","T":"In the same way, your Father in heaven does not want even one of these little ones to be lost."},
  "15": {"L":"And if thy brother sin against thee, go, show him his fault between thee and him alone; if he hear thee, thou hast gained thy brother.","M":"If your brother or sister sins against you, go and point out their fault, just between the two of you. If they listen to you, you have won them over.","T":"If a fellow believer sins against you, go to them privately and point it out. If they listen, you've restored the relationship."},
  "16": {"L":"But if he hear thee not, take with thee one or two more, that at the mouth of two witnesses or three every word may be established.","M":"But if they will not listen, take one or two others along, so that every matter may be established by the testimony of two or three witnesses.","T":"If they won't listen, bring one or two others—so that every word can be confirmed by two or three witnesses."},
  "17": {"L":"And if he refuse to hear them, tell it unto the church; and if he refuse to hear the church also, let him be unto thee as the Gentile and the publican.","M":"If they still refuse to listen, tell it to the church; and if they refuse to listen even to the church, treat them as you would a pagan or a tax collector.","T":"If they refuse to listen even to others, bring it before the community. And if they refuse even the community, treat them as you would an outsider."},
  "18": {"L":"Verily I say unto you, what things soever ye shall bind on earth shall be bound in heaven; and what things soever ye shall loose on earth shall be loosed in heaven.","M":"Truly I tell you, whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven.","T":"I tell you truly—whatever you bind on earth will be bound in heaven, and whatever you release on earth will be released in heaven."},
  "19": {"L":"Again I say unto you, that if two of you shall agree on earth as touching anything that they shall ask, it shall be done for them of my Father who is in heaven.","M":"Again, truly I tell you that if two of you on earth agree about anything they ask for, it will be done for them by my Father in heaven.","T":"Furthermore, if two of you agree together on earth about anything you ask for, my Father in heaven will do it for you."},
  "20": {"L":"For where two or three are gathered together in my name, there am I in the midst of them.","M":"For where two or three gather in my name, there am I with them.","T":"Because where two or three gather in my name, I am right there among them."},
  "21": {"L":"Then came Peter and said to him: Lord, how oft shall my brother sin against me, and I forgive him? until seven times?","M":"Then Peter came to Jesus and asked: Lord, how many times shall I forgive my brother or sister who sins against me? Up to seven times?","T":"Peter came to Jesus with a question: Lord, how many times should I forgive someone who wrongs me? Seven times?"},
  "22": {"L":"Jesus saith unto him: I say not unto thee, Until seven times; but, Until seventy times seven.","M":"Jesus answered: I tell you, not seven times, but seventy-seven times.","T":"Jesus answered: Not seven times—seventy times seven."},
  "23": {"L":"Therefore is the kingdom of heaven likened unto a certain king, who would make a reckoning with his servants.","M":"Therefore, the kingdom of heaven is like a king who wanted to settle accounts with his servants.","T":"So the heavenly kingdom is like a king who decided to settle his accounts with his servants."},
  "24": {"L":"And when he had begun to reckon, one was brought unto him, that owed him ten thousand talents.","M":"As he began the settlement, a man who owed him ten thousand bags of gold was brought to him.","T":"When he began the process, a man was brought before him who owed ten thousand talents—an impossibly large sum."},
  "25": {"L":"But forasmuch as he had not wherewith to pay, his lord commanded him to be sold, and his wife, and children, and all that he had, and payment to be made.","M":"Since he was not able to pay, the master ordered that he and his wife and his children and all that he had be sold to repay the debt.","T":"Since he couldn't pay, the master ordered him to be sold—along with his wife, children, and everything he owned—to settle the debt."},
  "26": {"L":"The servant therefore fell down and worshipped him, saying: Lord, have patience with me, and I will pay thee all.","M":"At this the servant fell on his knees before him. Be patient with me, he begged, and I will pay back everything.","T":"The servant fell to his knees before him: Be patient with me, he begged, and I'll pay everything back."},
  "27": {"L":"And the lord of that servant, being moved with compassion, released him, and forgave him the debt.","M":"The servant's master took pity on him, cancelled the debt and let him go.","T":"The master felt compassion for him, cancelled the entire debt, and released him."},
  "28": {"L":"But that servant went out, and found one of his fellow-servants, who owed him a hundred shillings; and he laid hold on him, and took him by the throat, saying: Pay what thou owest.","M":"But when that servant went out, he found one of his fellow servants who owed him a hundred silver coins. He grabbed him and began to choke him. Pay back what you owe me! he demanded.","T":"But that same servant went out and found a colleague who owed him a hundred denarii—a small amount. He grabbed him by the throat: Pay back what you owe me!"},
  "29": {"L":"So his fellow-servant fell down and besought him, saying: Have patience with me, and I will pay thee.","M":"His fellow servant fell to his knees and begged him: Be patient with me, and I will pay it back.","T":"His colleague fell to his knees and begged: Be patient with me and I'll pay you back."},
  "30": {"L":"And he would not; but went and cast him into prison, till he should pay that which was due.","M":"But he refused. Instead, he went off and had the man thrown into prison until he could pay the debt.","T":"But he refused. He had the man thrown in prison until the debt was paid."},
  "31": {"L":"So when his fellow-servants saw what was done, they were exceeding sorry, and came and told unto their lord all that was done.","M":"When the other servants saw what had happened, they were outraged and went and told their master everything that had happened.","T":"When the other servants witnessed this, they were deeply disturbed. They went and reported everything to the master."},
  "32": {"L":"Then his lord called him unto him, and saith to him: Thou wicked servant, I forgave thee all that debt, because thou besoughtest me;","M":"Then the master called the servant in. You wicked servant, he said, I cancelled all that debt of yours because you begged me to.","T":"The master summoned him: You wicked servant! I cancelled your entire debt when you begged me."},
  "33": {"L":"shouldest not thou also have had mercy on thy fellow-servant, even as I had mercy on thee?","M":"Shouldn't you have had mercy on your fellow servant just as I had on you?","T":"Shouldn't you have shown your colleague the same mercy I showed you?"},
  "34": {"L":"And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due.","M":"In anger his master handed him over to the jailers to be tortured, until he should pay back all he owed.","T":"In his fury, the master handed him over to the jailers to be tortured until he had paid back everything."},
  "35": {"L":"So shall also my heavenly Father do unto you, if ye forgive not every one his brother from your hearts.","M":"This is how my heavenly Father will treat each of you unless you forgive your brother or sister from your heart.","T":"This is what my heavenly Father will do to you if you don't forgive your brother or sister from your heart."}
 },
 "19": {
  "1": {"L":"And it came to pass when Jesus had finished these words, he departed from Galilee, and came into the borders of Judaea beyond the Jordan;","M":"When Jesus had finished saying these things, he left Galilee and went into the region of Judea to the other side of the Jordan.","T":"When Jesus had finished speaking, he left Galilee and traveled to the region of Judea on the far side of the Jordan."},
  "2": {"L":"and great multitudes followed him; and he healed them there.","M":"Large crowds followed him, and he healed them there.","T":"Large crowds followed him, and he healed them there."},
  "3": {"L":"And there came unto him Pharisees, trying him, and saying: Is it lawful for a man to put away his wife for every cause?","M":"Some Pharisees came to him to test him. They asked: Is it lawful for a man to divorce his wife for any and every reason?","T":"Pharisees came to test him: Is it legal for a man to divorce his wife for any reason?"},
  "4": {"L":"And he answered and said: Have ye not read, that he who made them from the beginning made them male and female,","M":"Haven't you read, he replied, that at the beginning the Creator made them male and female,","T":"He replied: Haven't you read that from the beginning the Creator made them male and female,"},
  "5": {"L":"and said: For this cause shall a man leave his father and mother, and shall cleave to his wife; and the two shall become one flesh?","M":"and said: For this reason a man will leave his father and mother and be united to his wife, and the two will become one flesh?","T":"and said: For this reason a man will leave his father and mother and be joined to his wife, and the two shall become one flesh?"},
  "6": {"L":"So that they are no more two, but one flesh. What therefore God hath joined together, let not man put asunder.","M":"So they are no longer two, but one flesh. Therefore what God has joined together, let no one separate.","T":"So they are no longer two people but one. What God has joined together, no human being should separate."},
  "7": {"L":"They say unto him: Why then did Moses command to give a bill of divorcement, and to put her away?","M":"Why then, they asked, did Moses command that a man give his wife a certificate of divorce and send her away?","T":"Then why, they asked, did Moses command that a man give his wife a written divorce notice?"},
  "8": {"L":"He saith unto them: Moses for your hardness of heart suffered you to put away your wives; but from the beginning it hath not been so.","M":"Jesus replied: Moses permitted you to divorce your wives because your hearts were hard. But it was not this way from the beginning.","T":"Jesus replied: Moses allowed you to divorce your wives because of your moral stubbornness—but that was never God's original intention."},
  "9": {"L":"And I say unto you, Whosoever shall put away his wife, except for fornication, and shall marry another, committeth adultery; and he that marrieth her when she is put away committeth adultery.","M":"I tell you that anyone who divorces his wife, except for sexual immorality, and marries another woman commits adultery.","T":"I tell you: anyone who divorces his wife—except for sexual unfaithfulness—and marries another, commits adultery."},
  "10": {"L":"The disciples say unto him: If the case of the man is so with his wife, it is not expedient to marry.","M":"The disciples said to him: If this is the situation between a husband and wife, it is better not to marry.","T":"The disciples said: If that's the situation between a man and his wife, it's better not to get married at all."},
  "11": {"L":"But he said unto them: Not all men can receive this saying, but they to whom it is given.","M":"Jesus replied: Not everyone can accept this word, but only those to whom it has been given.","T":"Jesus replied: Not everyone can accept this—only those to whom it has been given."},
  "12": {"L":"For there are eunuchs, that were so born from their mother's womb; and there are eunuchs, that were made eunuchs by men; and there are eunuchs, that made themselves eunuchs for the kingdom of heaven's sake. He that is able to receive it, let him receive it.","M":"For there are eunuchs who were born that way, and there are eunuchs who have been made eunuchs by others, and there are those who choose to live like eunuchs for the sake of the kingdom of heaven. The one who can accept this should accept it.","T":"Some people are not wired for marriage from birth; some have been made that way by others; and some choose to forgo marriage for the sake of God's kingdom. Whoever is able to accept this should accept it."},
  "13": {"L":"Then were there brought unto him little children, that he should lay his hands on them, and pray; and the disciples rebuked them.","M":"Then people brought little children to Jesus for him to place his hands on them and pray for them. But the disciples rebuked them.","T":"People were bringing small children to Jesus so he could place his hands on them and pray. The disciples turned them away."},
  "14": {"L":"But Jesus said: Suffer the little children, and forbid them not, to come unto me; for of such is the kingdom of heaven.","M":"Jesus said: Let the little children come to me, and do not hinder them, for the kingdom of heaven belongs to such as these.","T":"Jesus said: Let the children come to me—don't stop them. The kingdom of heaven belongs to people like these."},
  "15": {"L":"And he laid his hands on them, and departed thence.","M":"When he had placed his hands on them, he went on from there.","T":"He placed his hands on them and then moved on."},
  "16": {"L":"And behold, one came to him and said: Teacher, what good thing shall I do, that I may have eternal life?","M":"Just then a man came up to Jesus and asked: Teacher, what good thing must I do to get eternal life?","T":"Then a man came to him: Teacher, what good thing must I do to receive eternal life?"},
  "17": {"L":"And he said unto him: Why askest thou me concerning that which is good? One there is who is good; but if thou wouldest enter into life, keep the commandments.","M":"Why do you ask me about what is good? Jesus replied. There is only One who is good. If you want to enter life, keep the commandments.","T":"Jesus replied: Why do you ask me about what is good? There is only One who is good. If you want to enter into life, keep the commandments."},
  "18": {"L":"He saith unto him: Which? And Jesus said: Thou shalt not kill, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,","M":"Which ones? he inquired. Jesus replied: You shall not murder, you shall not commit adultery, you shall not steal, you shall not give false testimony,","T":"Which ones? the man asked. Jesus said: Don't murder, don't commit adultery, don't steal, don't lie in court,"},
  "19": {"L":"Honour thy father and thy mother; and, Thou shalt love thy neighbour as thyself.","M":"honour your father and mother, and love your neighbour as yourself.","T":"honor your father and mother, and love your neighbor as yourself."},
  "20": {"L":"The young man saith unto him: All these things have I observed; what lack I yet?","M":"All these I have kept, the young man said. What do I still lack?","T":"I've kept all these, the young man said. What am I still missing?"},
  "21": {"L":"Jesus said unto him: If thou wouldest be perfect, go, sell that which thou hast, and give to the poor, and thou shalt have treasure in heaven; and come, follow me.","M":"Jesus answered: If you want to be perfect, go, sell your possessions and give to the poor, and you will have treasure in heaven. Then come, follow me.","T":"Jesus replied: If you want to be complete, go sell everything you own and give the money to the poor—you'll have treasure in heaven. Then come and follow me."},
  "22": {"L":"But when the young man heard the saying, he went away sorrowful; for he was one that had great possessions.","M":"When the young man heard this, he went away sad, because he had great wealth.","T":"When the young man heard this, he walked away sad—because he was very wealthy."},
  "23": {"L":"And Jesus said unto his disciples: Verily I say unto you, It is hard for a rich man to enter into the kingdom of heaven.","M":"Then Jesus said to his disciples: Truly I tell you, it is hard for someone who is rich to enter the kingdom of heaven.","T":"Jesus said to his disciples: I tell you truly—it is very hard for a rich person to enter God's kingdom."},
  "24": {"L":"And again I say unto you, It is easier for a camel to go through a needle's eye, than for a rich man to enter into the kingdom of God.","M":"Again I tell you, it is easier for a camel to go through the eye of a needle than for someone who is rich to enter the kingdom of God.","T":"In fact, it's easier for a camel to go through the eye of a needle than for a wealthy person to enter God's kingdom."},
  "25": {"L":"And when the disciples heard it, they were astonished exceedingly, saying: Who then can be saved?","M":"When the disciples heard this, they were greatly astonished and asked: Who then can be saved?","T":"The disciples were stunned: Then who on earth can be saved?"},
  "26": {"L":"And Jesus looking upon them said to them: With men this is impossible; but with God all things are possible.","M":"Jesus looked at them and said: With man this is impossible, but with God all things are possible.","T":"Jesus looked at them steadily: With human beings it's impossible—but with God, everything is possible."},
  "27": {"L":"Then answered Peter and said unto him: Lo, we have left all, and followed thee; what then shall we have?","M":"Peter answered him: We have left everything to follow you! What then will there be for us?","T":"Peter spoke up: We've left everything to follow you. What will we receive?"},
  "28": {"L":"And Jesus said unto them: Verily I say unto you, that ye who have followed me, in the regeneration when the Son of man shall sit on the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.","M":"Jesus said to them: Truly I tell you, at the renewal of all things, when the Son of Man sits on his glorious throne, you who have followed me will also sit on twelve thrones, judging the twelve tribes of Israel.","T":"Jesus replied: I tell you truly—when everything is made new and the Son of Man sits on his glorious throne, you who have followed me will also sit on twelve thrones, ruling over the twelve tribes of Israel."},
  "29": {"L":"And every one that hath left houses, or brethren, or sisters, or father, or mother, or children, or lands, for my name's sake, shall receive a hundredfold, and shall inherit eternal life.","M":"And everyone who has left houses or brothers or sisters or father or mother or wife or children or fields for my sake will receive a hundred times as much and will inherit eternal life.","T":"Everyone who has left houses, brothers, sisters, father, mother, children, or land for my sake will receive a hundred times as much—and will inherit the life of the coming age."},
  "30": {"L":"But many shall be last that are first; and first that are last.","M":"But many who are first will be last, and many who are last will be first.","T":"But many who are first will be last, and many who are last will be first."}
 },
 "20": {
  "1": {"L":"For the kingdom of heaven is like unto a man that is a householder, who went out early in the morning to hire labourers into his vineyard.","M":"For the kingdom of heaven is like a landowner who went out early in the morning to hire workers for his vineyard.","T":"The kingdom of heaven is like a landowner who went out at dawn to hire workers for his vineyard."},
  "2": {"L":"And when he had agreed with the labourers for a penny a day, he sent them into his vineyard.","M":"He agreed to pay them a denarius for the day and sent them into his vineyard.","T":"He agreed to pay them a denarius for the day and sent them to work."},
  "3": {"L":"And he went out about the third hour, and saw others standing in the marketplace idle;","M":"About nine in the morning he went out and saw others standing in the market-place doing nothing.","T":"Around nine in the morning he went out and saw others standing idle in the marketplace."},
  "4": {"L":"and to them he said: Go ye also into the vineyard, and whatsoever is right I will give you. And they went their way.","M":"He told them: You also go and work in my vineyard, and I will pay you whatever is right. So they went.","T":"He told them: Go to the vineyard, and I'll pay you what's fair. They went."},
  "5": {"L":"Again he went out about the sixth hour and the ninth hour, and did likewise.","M":"He went out again about noon and about three in the afternoon and did the same thing.","T":"He did the same at noon and at three in the afternoon."},
  "6": {"L":"And about the eleventh hour he went out, and found others standing; and he saith unto them: Why stand ye here all the day idle?","M":"About five in the afternoon he went out and found still others standing around. He asked them: Why have you been standing here all day long doing nothing?","T":"Around five in the afternoon he went out and found still more standing around. He asked: Why have you been idle all day?"},
  "7": {"L":"They say unto him: Because no man hath hired us. He saith unto them: Go ye also into the vineyard.","M":"Because no one has hired us, they answered. He said to them: You also go and work in my vineyard.","T":"Nobody hired us, they replied. He said: Go to the vineyard then."},
  "8": {"L":"And when even was come, the lord of the vineyard said unto his steward: Call the labourers, and pay them their hire, beginning from the last unto the first.","M":"When evening came, the owner of the vineyard said to his foreman: Call the workers and pay them their wages, beginning with the last ones hired and going on to the first.","T":"When evening came, the vineyard owner told his foreman: Call the workers and pay them, starting with those hired last and going to those hired first."},
  "9": {"L":"And when they came that were hired about the eleventh hour, they received every man a penny.","M":"The workers who were hired about five in the afternoon came and each received a denarius.","T":"Those hired at five o'clock came and each received a denarius."},
  "10": {"L":"And when the first came, they supposed that they would receive more; and they likewise received every man a penny.","M":"So when those came who were hired first, they expected to receive more. But each one of them also received a denarius.","T":"When those hired first came, they expected more—but each of them also received one denarius."},
  "11": {"L":"And when they received it, they murmured against the householder,","M":"When they received it, they began to grumble against the landowner.","T":"They took it and grumbled at the landowner."},
  "12": {"L":"saying: These last have spent but one hour, and thou hast made them equal unto us, who have borne the burden of the day and the scorching heat.","M":"These who were hired last worked only one hour, they said, and you have made them equal to us who have borne the burden of the work and the heat of the day.","T":"These people who were hired last worked only one hour, and you've paid them the same as us—we who endured the whole day in the blazing heat!"},
  "13": {"L":"But he answered and said to one of them: Friend, I do thee no wrong; didst not thou agree with me for a penny?","M":"But he answered one of them: I am not being unfair to you, friend. Didn't you agree to work for a denarius?","T":"The landowner replied to one of them: Friend, I'm not cheating you. Didn't you agree to work for a denarius?"},
  "14": {"L":"Take up that which is thine, and go thy way; it is my will to give unto this last, even as unto thee.","M":"Take your pay and go. I want to give the one who was hired last the same as I gave you.","T":"Take what belongs to you and go. I choose to give the last person hired the same as you."},
  "15": {"L":"Is it not lawful for me to do what I will with mine own? or is thine eye evil, because I am good?","M":"Don't I have the right to do what I want with my own money? Or are you envious because I am generous?","T":"Don't I have the right to do what I want with what's mine? Or is your eye filled with envy because I am generous?"},
  "16": {"L":"So the last shall be first, and the first last.","M":"So the last will be first, and the first will be last.","T":"So the last will be first, and the first will be last."},
  "17": {"L":"And as Jesus was going up to Jerusalem, he took the twelve disciples apart, and in the way he said unto them,","M":"Now Jesus was going up to Jerusalem. On the way, he took the Twelve aside and said to them,","T":"As Jesus was going up to Jerusalem, he took the twelve disciples aside privately and said to them:"},
  "18": {"L":"Behold, we go up to Jerusalem; and the Son of man shall be delivered unto the chief priests and scribes; and they shall condemn him to death,","M":"We are going up to Jerusalem, and the Son of Man will be delivered over to the chief priests and the teachers of the law. They will condemn him to death","T":"We are going up to Jerusalem. The Son of Man will be handed over to the chief priests and religious scholars. They will sentence him to death"},
  "19": {"L":"and shall deliver him unto the Gentiles to mock, and to scourge, and to crucify; and the third day he shall be raised up.","M":"and will hand him over to the Gentiles to be mocked and flogged and crucified. On the third day he will be raised to life!","T":"and turn him over to the Gentiles to be mocked, flogged, and crucified. On the third day he will be raised."},
  "20": {"L":"Then came to him the mother of the sons of Zebedee with her sons, worshipping him, and asking a certain thing of him.","M":"Then the mother of Zebedee's sons came to Jesus with her sons and, kneeling down, asked a favour of him.","T":"Then the mother of Zebedee's sons came to Jesus with her sons and bowed before him with a request."},
  "21": {"L":"And he said unto her: What wouldest thou? She saith unto him: Command that these my two sons may sit, one on thy right hand, and one on the left hand, in thy kingdom.","M":"What is it you want? he asked. She said: Grant that one of these two sons of mine may sit at your right and the other at your left in your kingdom.","T":"He asked: What do you want? She replied: Promise me that in your kingdom these two sons of mine will sit at your right and left hand."},
  "22": {"L":"But Jesus answered and said: Ye know not what ye ask. Are ye able to drink the cup that I am about to drink? They say unto him: We are able.","M":"You don't know what you are asking, Jesus said to them. Can you drink the cup I am going to drink? We can, they answered.","T":"Jesus replied: You don't know what you're asking. Can you drink the cup I am about to drink? We can, they said."},
  "23": {"L":"He saith unto them: My cup indeed ye shall drink; but to sit on my right hand, and on my left hand, is not mine to give; but it is for them for whom it hath been prepared of my Father.","M":"Jesus said to them: You will indeed drink from my cup, but to sit at my right or left is not for me to grant. These places belong to those for whom they have been prepared by my Father.","T":"Jesus said: You will drink my cup—but the seats at my right and left are not mine to give. They belong to those for whom my Father has prepared them."},
  "24": {"L":"And when the ten heard it, they were moved with indignation concerning the two brethren.","M":"When the ten heard about this, they were indignant with the two brothers.","T":"When the other ten heard this, they were furious with the two brothers."},
  "25": {"L":"But Jesus called them unto him, and said: Ye know that the rulers of the Gentiles lord it over them, and their great ones exercise authority over them.","M":"Jesus called them together and said: You know that the rulers of the Gentiles lord it over them, and their high officials exercise authority over them.","T":"Jesus called them together: You know that the rulers of the Gentiles dominate their people—and their leaders use authority as a tool of power."},
  "26": {"L":"Not so shall it be among you: but whosoever would become great among you shall be your servant;","M":"Not so with you. Instead, whoever wants to become great among you must be your servant,","T":"That's not how things work among you. Whoever wants to be great among you must be your servant."},
  "27": {"L":"and whosoever would be first among you shall be your servant;","M":"and whoever wants to be first must be your slave—","T":"And whoever wants to be first must be everyone's slave."},
  "28": {"L":"even as the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many.","M":"just as the Son of Man did not come to be served, but to serve, and to give his life as a ransom for many.","T":"Just as the Son of Man didn't come to be served but to serve—and to give his life as the ransom price for many."},
  "29": {"L":"And as they went out from Jericho, a great multitude followed him.","M":"As Jesus and his disciples were leaving Jericho, a large crowd followed him.","T":"As Jesus and his disciples were leaving Jericho, a large crowd followed them."},
  "30": {"L":"And behold, two blind men sitting by the way side, when they heard that Jesus was passing by, cried out, saying: Lord, have mercy on us, thou son of David.","M":"Two blind men were sitting by the roadside, and when they heard that Jesus was going by, they shouted: Lord, Son of David, have mercy on us!","T":"Two blind men were sitting by the roadside. When they heard Jesus was passing, they shouted: Lord, Son of David, have mercy on us!"},
  "31": {"L":"And the multitude rebuked them, that they should hold their peace; but they cried out the more, saying: Lord, have mercy on us, thou son of David.","M":"The crowd rebuked them and told them to be quiet, but they shouted all the louder: Lord, Son of David, have mercy on us!","T":"The crowd tried to silence them, but they only shouted louder: Lord, Son of David, have mercy on us!"},
  "32": {"L":"And Jesus stood still, and called them, and said: What will ye that I should do unto you?","M":"Jesus stopped and called them. What do you want me to do for you? he asked.","T":"Jesus stopped and called them: What do you want me to do for you?"},
  "33": {"L":"They say unto him: Lord, that our eyes may be opened.","M":"Lord, they answered, we want our sight.","T":"Lord, they answered, we want to see."},
  "34": {"L":"And Jesus, being moved with compassion, touched their eyes; and straightway they received their sight, and followed him.","M":"Jesus had compassion on them and touched their eyes. Immediately they received their sight and followed him.","T":"Jesus felt deep compassion and touched their eyes. Instantly they could see, and they followed him."}
 },
 "21": {
  "1": {"L":"And when they drew nigh unto Jerusalem, and came unto Bethphage, unto the mount of Olives, then Jesus sent two disciples,","M":"As they approached Jerusalem and came to Bethphage on the Mount of Olives, Jesus sent two disciples,","T":"As they neared Jerusalem and reached Bethphage on the Mount of Olives, Jesus sent two disciples ahead."},
  "2": {"L":"saying unto them: Go into the village that is over against you, and straightway ye shall find an ass tied, and a colt with her; loose them, and bring them unto me.","M":"saying to them: Go to the village ahead of you, and at once you will find a donkey tied there, with her colt by her. Untie them and bring them to me.","T":"Go to the village just ahead, he said. You'll find a donkey tied up and her colt beside her. Untie them and bring them to me."},
  "3": {"L":"And if any one say aught unto you, ye shall say: The Lord hath need of them; and straightway he will send them.","M":"If anyone says anything to you, say that the Lord needs them, and he will send them right away.","T":"If anyone questions you, just say: The Lord needs them—and they'll let you take them."},
  "4": {"L":"Now this is come to pass, that it might be fulfilled which was spoken through the prophet, saying:","M":"This took place to fulfil what was spoken through the prophet:","T":"This happened to fulfill the words of the prophet:"},
  "5": {"L":"Tell ye the daughter of Zion, Behold, thy King cometh unto thee, Meek, and riding upon an ass, And upon a colt the foal of an ass.","M":"Say to Daughter Zion: See, your king comes to you, gentle and riding on a donkey, and on a colt, the foal of a donkey.","T":"Tell the daughter of Zion: Your King is coming to you—humble, riding on a donkey, the foal of a working animal."},
  "6": {"L":"And the disciples went, and did even as Jesus appointed them,","M":"The disciples went and did as Jesus had instructed them.","T":"The disciples went and did as Jesus had told them."},
  "7": {"L":"and brought the ass, and the colt, and put on them their garments; and he sat thereon.","M":"They brought the donkey and the colt and placed their cloaks on them for Jesus to sit on.","T":"They brought the donkey and colt, spread their cloaks on them, and Jesus sat on them."},
  "8": {"L":"And the most part of the multitude spread their garments in the way; and others cut branches from the trees, and spread them in the way.","M":"A very large crowd spread their cloaks on the road, while others cut branches from the trees and spread them on the road.","T":"A very large crowd spread their cloaks on the road; others cut branches from trees and scattered them in the path."},
  "9": {"L":"And the multitudes that went before him, and that followed, cried, saying: Hosanna to the son of David: Blessed is he that cometh in the name of the Lord; Hosanna in the highest.","M":"The crowds that went ahead of him and those that followed shouted: Hosanna to the Son of David! Blessed is he who comes in the name of the Lord! Hosanna in the highest heaven!","T":"The crowds going ahead and those following behind all shouted: Hosanna to the Son of David! Blessed is the one who comes in the name of the Lord! Hosanna in the highest!"},
  "10": {"L":"And when he was come into Jerusalem, all the city was stirred, saying: Who is this?","M":"When Jesus entered Jerusalem, the whole city was stirred and asked: Who is this?","T":"When Jesus entered Jerusalem, the whole city was in an uproar: Who is this?"},
  "11": {"L":"And the multitudes said: This is the prophet, Jesus, from Nazareth of Galilee.","M":"The crowds answered: This is Jesus, the prophet from Nazareth in Galilee.","T":"The crowds said: This is Jesus, the prophet from Nazareth in Galilee."},
  "12": {"L":"And Jesus entered into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the money-changers, and the seats of them that sold the doves;","M":"Jesus entered the temple courts and drove out all who were buying and selling there. He overturned the tables of the money-changers and the benches of those selling doves.","T":"Jesus entered the temple and drove out everyone who was buying and selling there. He overturned the money-changers' tables and the seats of those selling doves."},
  "13": {"L":"and he saith unto them: It is written, My house shall be called a house of prayer; but ye make it a den of robbers.","M":"It is written, he said to them: My house will be called a house of prayer, but you are making it a den of robbers.","T":"He said: Scripture says, My house will be called a house of prayer—but you've turned it into a robbers' hideout."},
  "14": {"L":"And the blind and the lame came to him in the temple; and he healed them.","M":"The blind and the lame came to him at the temple, and he healed them.","T":"The blind and lame came to him in the temple and he healed them."},
  "15": {"L":"But when the chief priests and the scribes saw the wonderful things that he did, and the children that were crying in the temple and saying: Hosanna to the son of David; they were moved with indignation,","M":"But when the chief priests and the teachers of the law saw the wonderful things he did and the children shouting in the temple courts: Hosanna to the Son of David, they were indignant.","T":"When the chief priests and religious scholars saw the miracles and heard children in the temple shouting Hosanna to the Son of David, they were indignant."},
  "16": {"L":"and said unto him: Hearest thou what these are saying? And Jesus saith unto them: Yea; did ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?","M":"Do you hear what these children are saying? they asked him. Yes, replied Jesus, have you never read: From the lips of children and infants you, Lord, have called forth your praise?","T":"They demanded: Do you hear what these children are saying? Yes, Jesus replied. Haven't you ever read: From the mouths of children and infants you have prepared praise?"},
  "17": {"L":"And he left them, and went forth out of the city to Bethany, and lodged there.","M":"And he left them and went out of the city to Bethany, where he spent the night.","T":"And he left them, went out to Bethany, and spent the night there."},
  "18": {"L":"Now in the morning as he returned to the city, he hungered.","M":"Early in the morning, as Jesus was on his way back to the city, he was hungry.","T":"Early the next morning as he was returning to the city, he was hungry."},
  "19": {"L":"And seeing a fig tree by the way side, he came to it, and found nothing thereon, but leaves only; and he saith unto it: Let there be no fruit from thee henceforward for ever. And immediately the fig tree withered away.","M":"Seeing a fig tree by the road, he went up to it but found nothing on it except leaves. Then he said to it: May you never bear fruit again! Immediately the tree withered.","T":"He saw a fig tree by the road and went to it, but found nothing but leaves. He said to it: May you never produce fruit again! And the fig tree immediately withered."},
  "20": {"L":"And when the disciples saw it, they marvelled, saying: How did the fig tree immediately wither away?","M":"When the disciples saw this, they were amazed. How did the fig tree wither so quickly? they asked.","T":"The disciples were astonished: How did the fig tree wither so quickly?"},
  "21": {"L":"And Jesus answered and said unto them: Verily I say unto you, If ye have faith, and doubt not, ye shall not only do what is done to the fig tree, but even if ye shall say unto this mountain, Be thou taken up and cast into the sea, it shall be done.","M":"Jesus replied: Truly I tell you, if you have faith and do not doubt, not only can you do what was done to the fig tree, but also you can say to this mountain: Go, throw yourself into the sea, and it will be done.","T":"Jesus replied: I tell you truly—if you have faith and don't doubt, you can do not only what was done to this fig tree, but even say to this mountain: Be lifted up and hurled into the sea—and it will happen."},
  "22": {"L":"And all things, whatsoever ye shall ask in prayer, believing, ye shall receive.","M":"If you believe, you will receive whatever you ask for in prayer.","T":"Everything you ask for in prayer—if you believe—you will receive."},
  "23": {"L":"And when he was come into the temple, the chief priests and the elders of the people came unto him as he was teaching, and said: By what authority doest thou these things? and who gave thee this authority?","M":"Jesus entered the temple courts, and, while he was teaching, the chief priests and the elders of the people came to him. By what authority are you doing these things? they asked. And who gave you this authority?","T":"When he had entered the temple and was teaching, the chief priests and elders came to him: By what authority are you doing these things? Who gave you this authority?"},
  "24": {"L":"And Jesus answered and said unto them: I also will ask you one question, which if ye tell me, I likewise will tell you by what authority I do these things.","M":"Jesus replied: I will also ask you one question. If you answer me, I will tell you by what authority I am doing these things.","T":"Jesus replied: I'll ask you one question too—if you answer me, I'll tell you by what authority I do these things."},
  "25": {"L":"The baptism of John, whence was it? from heaven or from men? And they reasoned with themselves, saying: If we shall say, From heaven; he will say unto us, Why then did ye not believe him?","M":"John's baptism—where did it come from? Was it from heaven, or of human origin? They discussed it among themselves and said: If we say: From heaven, he will ask: Then why didn't you believe him?","T":"John's baptism—was it from heaven or from human beings? They debated privately: If we say from heaven, he'll ask why we didn't believe him."},
  "26": {"L":"But if we shall say, From men; we fear the multitude; for all hold John as a prophet.","M":"But if we say: Of human origin—we are afraid of the people, for they all hold that John was a prophet.","T":"But if we say from human beings, we're afraid of the crowd—everyone considers John a prophet."},
  "27": {"L":"And they answered Jesus, and said: We know not. He also said unto them: Neither tell I you by what authority I do these things.","M":"So they answered Jesus: We don't know. Then he said: Neither will I tell you by what authority I am doing these things.","T":"So they answered: We don't know. Then Jesus said: Neither will I tell you by what authority I do these things."},
  "28": {"L":"But what think ye? A man had two sons; and he came to the first, and said: Son, go work to-day in the vineyard.","M":"What do you think? There was a man who had two sons. He went to the first and said: Son, go and work today in the vineyard.","T":"What do you think? A man had two sons. He went to the first and said: Son, go work in the vineyard today."},
  "29": {"L":"And he answered and said: I will not; but afterward he repented himself, and went.","M":"I will not, he answered, but later he changed his mind and went.","T":"I won't, the son replied—but later he changed his mind and went."},
  "30": {"L":"And he came to the second, and said likewise. And he answered and said: I go, sir; and went not.","M":"Then the father went to the other son and said the same thing. He answered: I will, sir, but he did not go.","T":"The father went to the other son and said the same thing. He answered: Sure, I'll go—but he never did."},
  "31": {"L":"Which of the two did the will of his father? They say: The first. Jesus saith unto them: Verily I say unto you, that the publicans and the harlots go into the kingdom of God before you.","M":"Which of the two did what his father wanted? The first, they answered. Jesus said to them: Truly I tell you, the tax collectors and the prostitutes are entering the kingdom of God ahead of you.","T":"Which of the two did what his father wanted? The first one, they said. I tell you plainly, Jesus replied: tax collectors and prostitutes are entering God's kingdom ahead of you."},
  "32": {"L":"For John came unto you in the way of righteousness, and ye believed him not; but the publicans and the harlots believed him; and ye, when ye saw it, did not even repent yourselves afterward, that ye might believe him.","M":"For John came to you to show you the way of righteousness, and you did not believe him, but the tax collectors and the prostitutes did. And even after you saw this, you did not repent and believe him.","T":"John came to show you the path of righteousness, and you refused to believe him. But the tax collectors and prostitutes did believe him. And even after seeing that, you didn't change your minds and believe."},
  "33": {"L":"Hear another parable: There was a man that was a householder, who planted a vineyard, and set a hedge about it, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into another country.","M":"Listen to another parable: There was a landowner who planted a vineyard. He put a wall around it, dug a winepress in it and built a watchtower. Then he rented the vineyard to some farmers and moved to another place.","T":"Listen to another parable. A landowner planted a vineyard, built a wall around it, dug a winepress, and erected a watchtower. Then he leased it to tenant farmers and went abroad."},
  "34": {"L":"And when the season of the fruits drew near, he sent his servants to the husbandmen, to receive his fruits.","M":"When the harvest time approached, he sent his servants to the tenants to collect his fruit.","T":"When harvest time came, he sent his servants to collect his share of the produce."},
  "35": {"L":"And the husbandmen took his servants, and beat one, and killed another, and stoned another.","M":"The tenants seized his servants; they beat one, killed another, and stoned a third.","T":"The tenants seized his servants—they beat one, killed another, and stoned a third."},
  "36": {"L":"Again, he sent other servants more than the first; and they did unto them in like manner.","M":"Then he sent other servants to them, more than the first time, and the tenants treated them the same way.","T":"He sent more servants—more than before—and they were treated the same way."},
  "37": {"L":"But afterward he sent unto them his son, saying: They will reverence my son.","M":"Last of all, he sent his son to them. They will respect my son, he said.","T":"Finally he sent his son: They will respect my son, he thought."},
  "38": {"L":"But the husbandmen, when they saw the son, said among themselves: This is the heir; come, let us kill him, and take his inheritance.","M":"But when the tenants saw the son, they said to each other: This is the heir. Come, let's kill him and take his inheritance.","T":"But when the tenants saw the son coming, they said to each other: This is the heir—let's kill him and take his inheritance for ourselves!"},
  "39": {"L":"And they took him, and cast him out of the vineyard, and killed him.","M":"So they took him and threw him out of the vineyard and killed him.","T":"They seized him, threw him out of the vineyard, and murdered him."},
  "40": {"L":"When therefore the lord of the vineyard shall come, what will he do unto those husbandmen?","M":"Therefore, when the owner of the vineyard comes, what will he do to those tenants?","T":"When the vineyard owner comes, what will he do to those tenants?"},
  "41": {"L":"They say unto him: He will miserably destroy those miserable men, and will let out the vineyard unto other husbandmen, who shall render him the fruits in their seasons.","M":"He will bring those wretches to a wretched end, they replied, and he will rent the vineyard to other tenants, who will give him his share of the crop at harvest time.","T":"He will bring those wretches to a wretched end, they said, and lease the vineyard to other farmers who will give him his rightful share at harvest."},
  "42": {"L":"Jesus saith unto them: Did ye never read in the scriptures, The stone which the builders rejected, the same was made the head of the corner; This was from the Lord, and it is marvellous in our eyes?","M":"Jesus said to them: Have you never read in the Scriptures: The stone the builders rejected has become the cornerstone; the Lord has done this, and it is marvellous in our eyes?","T":"Jesus said: Haven't you read in the Scriptures: The stone the builders threw away has become the cornerstone. The Lord did this, and it is astonishing to us."},
  "43": {"L":"Therefore say I unto you, The kingdom of God shall be taken away from you, and shall be given to a nation bringing forth the fruits thereof.","M":"Therefore I tell you that the kingdom of God will be taken away from you and given to a people who will produce its fruit.","T":"I tell you: God's kingdom will be taken from you and given to a people who will produce its fruit."},
  "44": {"L":"And he that falleth on this stone shall be broken to pieces; but on whomsoever it shall fall, it will scatter him as dust.","M":"Anyone who falls on this stone will be broken to pieces; anyone on whom it falls will be crushed.","T":"Anyone who stumbles on this stone will be shattered. And anyone it falls on will be crushed to dust."},
  "45": {"L":"And when the chief priests and the Pharisees heard his parables, they perceived that he spake of them.","M":"When the chief priests and the Pharisees heard Jesus' parables, they knew he was talking about them.","T":"When the chief priests and Pharisees heard his parables, they realized he was talking about them."},
  "46": {"L":"And when they sought to lay hold on him, they feared the multitudes, because they took him for a prophet.","M":"They looked for a way to arrest him, but they were afraid of the crowd because the people held that he was a prophet.","T":"They were looking for a way to arrest him—but they feared the crowds, who regarded him as a prophet."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'matthew')
        for ch, verses in MATTHEW.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'matthew', data)
    print('Matthew chapters 15-21 written.')

if __name__ == '__main__':
    main()
